sp_page.css:
/* =========================================
   1. PREMIUM "ACADEMIC" BACKGROUND
   ========================================= */
body, main.body, section.page, .sp-page-root {
    background-color: #f0f4f8 !important;
    background-image: radial-gradient(#cbd5e1 1.5px, transparent 1.5px) !important;
    background-size: 25px 25px !important;
    min-height: 100vh;
    font-family: 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
}

.wrapper-xl { padding-top: 20px !important; }

/* =========================================
   2. DASHBOARD ENTRANCE ANIMATION
   ========================================= */
.container {
    animation: slideUpFade 0.8s cubic-bezier(0.16, 1, 0.3, 1) forwards;
    opacity: 0;
}

@keyframes slideUpFade {
    0% { opacity: 0; transform: translateY(40px); }
    100% { opacity: 1; transform: translateY(0); }
}

/* =========================================
   3. ANIMATED GREETING TEXT
   ========================================= */
h1, h2.text-center {
    font-weight: 900 !important;
    letter-spacing: 1px;
    background: linear-gradient(135deg, #0f172a 0%, #0ea5e9 100%);
    background-size: 200% auto;
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    animation: textShine 4s linear infinite;
    padding-bottom: 25px !important;
    text-shadow: 0 4px 10px rgba(14, 165, 233, 0.1);
}

@keyframes textShine {
    to { background-position: 200% center; }
}

/* =========================================
   4. FORCE REPORTS/CHARTS TO FLOAT
   ========================================= */
/* Target ONLY the report panels here */
.panel {
    background-color: #ffffff !important;
    border-radius: 16px !important;
    border: 1px solid rgba(226, 232, 240, 0.8) !important;
    box-shadow: 0 10px 30px rgba(15, 23, 42, 0.06) !important;
    transition: all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275) !important;
    overflow: hidden !important;
    margin-bottom: 25px !important;
}

.panel:hover {
    transform: translateY(-6px) !important;
    box-shadow: 0 20px 40px rgba(14, 165, 233, 0.12) !important;
    border-color: rgba(14, 165, 233, 0.4) !important;
}

.panel-heading {
    background-color: #ffffff !important;
    border-bottom: 1px solid #f1f5f9 !important;
    padding: 18px 20px !important;
}

.panel-title {
    font-weight: 800 !important;
    color: #1e293b !important;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    font-size: 14px !important;
}

.panel-body { padding: 20px !important; }

/* =========================================
   5. BULLETPROOF ICON LINKS (STUDENT/ASSIGNMENT)
   ========================================= */
/* Aggressively target the anchor tag to guarantee it registers the mouse */
a.sp-icon-link, .sp-icon-link {
    display: block !important;
    background-color: #ffffff !important;
    border-radius: 16px !important;
    border: 1px solid rgba(226, 232, 240, 0.8) !important;
    box-shadow: 0 10px 30px rgba(15, 23, 42, 0.06) !important;
    padding: 30px 20px !important;
    text-align: center !important;
    text-decoration: none !important;
    transition: all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275) !important;
    margin-bottom: 25px !important;
}

/* The Lift and Glow Effect */
a.sp-icon-link:hover, .sp-icon-link:hover {
    transform: translateY(-10px) !important; 
    box-shadow: 0 15px 35px rgba(14, 165, 233, 0.2) !important; 
    border-color: #bae6fd !important; 
    text-decoration: none !important;
}

/* The Big Icons inside the link */
a.sp-icon-link .fa, .sp-icon-link .fa {
    color: #0ea5e9 !important; 
    font-size: 55px !important; 
    display: block !important;
    margin-bottom: 15px !important;
    transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275) !important;
}

/* Make the icon pop inside the card */
a.sp-icon-link:hover .fa, .sp-icon-link:hover .fa {
    transform: scale(1.2) !important; 
    color: #0284c7 !important; 
    filter: drop-shadow(0px 4px 8px rgba(2, 132, 199, 0.3)) !important; 
}

/* Icon Link Text */
a.sp-icon-link h2, .sp-icon-link h2 {
    color: #334155 !important;
    font-weight: 700 !important;
    font-size: 18px !important;
    margin: 0 !important;
    transition: color 0.3s ease !important;
}

/* Change text color on hover */
a.sp-icon-link:hover h2, .sp-icon-link:hover h2 {
    color: #0ea5e9 !important;
}

/* =========================================
   6. TOP MENU & DROPDOWN ANIMATIONS
   ========================================= */
/* Top Menu Underline Effect */
ul.nav.navbar-nav > li > a {
    position: relative;
    transition: color 0.3s ease !important;
    font-weight: 600 !important;
}

ul.nav.navbar-nav > li > a:hover {
    color: #0ea5e9 !important; 
    background-color: transparent !important;
}

ul.nav.navbar-nav > li > a::after {
    content: '';
    position: absolute;
    width: 0;
    height: 2px;
    bottom: 10px; 
    left: 50%;
    background-color: #0ea5e9;
    transition: all 0.3s ease-in-out;
    transform: translateX(-50%); 
}

ul.nav.navbar-nav > li > a:hover::after {
    width: 70%; 
}

/* --- THE DROPDOWN MENU ANIMATION --- */
.dropdown-menu {
    border-radius: 12px !important;
    border: 1px solid #e2e8f0 !important;
    box-shadow: 0 15px 35px rgba(15, 23, 42, 0.1) !important;
    padding: 10px 0 !important;
    margin-top: 10px !important;
    
    /* Smooth slide-down and fade-in */
    animation: dropdownSlideFade 0.3s cubic-bezier(0.16, 1, 0.3, 1) forwards !important;
    transform-origin: top center;
}

@keyframes dropdownSlideFade {
    0% { opacity: 0; transform: translateY(-15px); }
    100% { opacity: 1; transform: translateY(0); }
}

/* Dropdown List Items Hover Effect */
.dropdown-menu > li > a {
    padding: 12px 20px !important;
    font-weight: 600 !important;
    color: #475569 !important;
    transition: all 0.2s ease !important;
}

.dropdown-menu > li > a:hover {
    background-color: #f0f9ff !important; /* Soft blue background */
    color: #0ea5e9 !important; /* Bright blue text */
    padding-left: 28px !important; /* Smoothly slides the text to the right */
}

/* Profile Bubble Hover */
.navbar-nav .dropdown-toggle .avatar-container {
    transition: all 0.3s ease !important;
}

.navbar-nav .dropdown-toggle:hover .avatar-container {
    transform: scale(1.1);
    box-shadow: 0 0 10px rgba(14, 165, 233, 0.4);
}
